/** \brief Filter represents the base filter class. All filters must inherit from this interface.
  * \author Radu B. Rusu
  * \ingroup filters
  */
template<>
class PCL_EXPORTS Filter<pcl::PCLPointCloud2> : public PCLBase<pcl::PCLPointCloud2>
{
  public:
    using Ptr = shared_ptr<Filter<pcl::PCLPointCloud2> >;
    using ConstPtr = shared_ptr<const Filter<pcl::PCLPointCloud2> >;

    using PCLPointCloud2 = pcl::PCLPointCloud2;
    using PCLPointCloud2Ptr = PCLPointCloud2::Ptr;
    using PCLPointCloud2ConstPtr = PCLPointCloud2::ConstPtr;

    /** \brief Empty constructor.
      * \param[in] extract_removed_indices set to true if the filtered data indices should be saved in a
      * separate list. Default: false.
      */

size_t Validator::getThresholdPointCloud(
  const autoware_perception_msgs::msg::DetectedObject & object)
{
  const auto object_label_id = object.classification.front().label;
  const auto object_distance = std::hypot(
    object.kinematics.pose_with_covariance.pose.position.x,
    object.kinematics.pose_with_covariance.pose.position.y);
  size_t threshold_pc = std::clamp(
    static_cast<size_t>(std::lround(
      points_num_threshold_param_.min_points_and_distance_ratio.at(object_label_id) /
      object_distance)),
    static_cast<size_t>(points_num_threshold_param_.min_points_num.at(object_label_id)),
    static_cast<size_t>(points_num_threshold_param_.max_points_num.at(object_label_id)));
  return threshold_pc;
}
